    actix_server::Server::build()
        .bind("echo", ("127.0.0.1", 8080), || {
            HttpService::build()
                // handles HTTP/1.1 only
                .h1(handle_request)
                // No TLS
                .tcp()
        })?
        .run()
        .await
}

